import AnimeCard from "./AnimeCard.astro";

interface StatusInfo {
	text: string;
	class: string;
	icon: string;
}

interface AnimeItem {
	title: string;
	cover: string;
	link: string;
	status: string;
	rating: number;
	progress: number;
	totalEpisodes: number;
	description: string;
	year: string;
	studio: string;
	genre: string[];
}

interface Props {
	visibleAnimeList: AnimeItem[];
	hiddenAnimeList: AnimeItem[];
	statusMap: Record<string, StatusInfo>;
	yearLabel: string;
	studioLabel: string;
}

const { visibleAnimeList, hiddenAnimeList, statusMap, yearLabel, studioLabel } =
